import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';
import { API_URL } from '../config';

const Login = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [errorMsg, setErrorMsg] = useState('');
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrorMsg('');
    try {
      const res = await fetch(`${API_URL}/api/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      });
      const data = await res.json();
      if (res.ok) {
        login(data.token);
        navigate('/');
      } else {
        setErrorMsg(data.msg === 'Invalid credentials' ? '登录失败，请检查用户名或密码。' : data.msg);
      }
    } catch (err) {
      console.error(err);
      setErrorMsg('服务器错误，请稍后再试。');
    }
  };

  return (
    <div className="form-container">
      <h2>登录</h2>
      {errorMsg && <div style={{ color: '#e30000', marginBottom: '15px', fontSize: '14px', fontWeight: 500 }}>{errorMsg}</div>}
      <form onSubmit={handleSubmit}>
        <input type="text" placeholder="Apple ID (用户名)" value={username} onChange={(e) => setUsername(e.target.value)} required />
        <input type="password" placeholder="密码" value={password} onChange={(e) => setPassword(e.target.value)} required />
        <button type="submit">继续</button>
      </form>
      <p>还没有账号？ <a href="/register">立即创建。</a></p>
    </div>
  );
};

export default Login;
